.tabber .tabbertab{
border:none;
}
ul.tabbernav{
border-bottom:none;
font-family:'MIANFEIZITI';
font-weight:normal;
}
ul.tabbernav li a{
border:none;
background:#f2f2f2;
transition:background 0.5s ease-out;
border-radius:15px;
}
ul.tabbernav li{
margin:15px 0px 0px 25px;
border-radius:15px;
position:relative;
}
ul.tabbernav li a:link{
color:#515563;
font-size:16px;
}
ul.tabbernav li.tabberactive a:hover,
ul.tabbernav li a:hover{
background:#BFBEBF;
border-radius:15px;
border-bottom:none;
}
ul.tabbernav li.tabberactive a{
    background: #313435;
    color: #f2f2f2;
    border-radius: 12px;
    border-bottom:none;
}
ul.tabbernav li::before{
content:"";
position:absolute;
width:20px;
height:20px;
left:10px;
top:4px;
}
ul.tabbernav li a,
ul.tabbernav li.tabberactive a{
    display:block;
    width:120%;
    text-align:end;
    height:30px;
    line-height:30px;
    padding:0 10px;
}
